function shuffleFolderQueueD(count: number): number[] {
  const queue: number[] = [];
  for (let i = 0; i < count; i++) {
    queue.push(i);
  }
  for (let j = queue.length - 1; j > 0; j--) {
    const k = Math.floor(Math.random() * (j + 1));
    const temp = queue[j];
    queue[j] = queue[k];
    queue[k] = temp;
  }
  return queue;
}

