  const next = new Set<number>(selected);
  if (selectAll) {
    next.clear();
    for (let i = 0; i < total; i++) {
      next.add(i);
    }
    return next;
  }
  if (next.has(index)) {
    next.delete(index);
  } else {
    next.add(index);
  }
  return next;
}

